    tempRoot = await mkdtemp(join(tmpdir(), 'cursor-plugin-install-'));
    homeDir = join(tempRoot, 'home');
    await mkdir(homeDir, { recursive: true });
    vi.spyOn(await import('node:os'), 'homedir').mockReturnValue(homeDir);
  });

